from flask import Flask, render_template, redirect, url_for, request, abort
from werkzeug.utils import secure_filename
import os
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'
UPLOAD_FOLDER = 'uploads'

if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

# Utility functions for reading and writing data files

def read_jobs():
    jobs_path = os.path.join(DATA_DIR, 'jobs.txt')
    jobs = []
    try:
        with open(jobs_path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 9:
                    continue
                job = {
                    'job_id': int(fields[0]),
                    'title': fields[1],
                    'company_id': int(fields[2]),
                    'location': fields[3],
                    'salary_min': int(fields[4]),
                    'salary_max': int(fields[5]),
                    'category': fields[6],
                    'description': fields[7],
                    'posted_date': fields[8]
                }
                jobs.append(job)
    except FileNotFoundError:
        pass
    return jobs


def write_jobs(jobs):
    jobs_path = os.path.join(DATA_DIR, 'jobs.txt')
    with open(jobs_path, 'w', encoding='utf-8') as f:
        for job in jobs:
            line = f"{job['job_id']}|{job['title']}|{job['company_id']}|{job['location']}|{job['salary_min']}|{job['salary_max']}|{job['category']}|{job['description']}|{job['posted_date']}"
            f.write(line + '\n')


def read_companies():
    companies_path = os.path.join(DATA_DIR, 'companies.txt')
    companies = []
    try:
        with open(companies_path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 6:
                    continue
                company = {
                    'company_id': int(fields[0]),
                    'company_name': fields[1],
                    'industry': fields[2],
                    'location': fields[3],
                    'employee_count': int(fields[4]),
                    'description': fields[5]
                }
                companies.append(company)
    except FileNotFoundError:
        pass
    return companies


def write_companies(companies):
    companies_path = os.path.join(DATA_DIR, 'companies.txt')
    with open(companies_path, 'w', encoding='utf-8') as f:
        for c in companies:
            line = f"{c['company_id']}|{c['company_name']}|{c['industry']}|{c['location']}|{c['employee_count']}|{c['description']}"
            f.write(line + '\n')


def read_categories():
    categories_path = os.path.join(DATA_DIR, 'categories.txt')
    categories = []
    try:
        with open(categories_path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 3:
                    continue
                # Only the category_name is needed for context
                categories.append(fields[1])
    except FileNotFoundError:
        pass
    return categories


def read_applications():
    applications_path = os.path.join(DATA_DIR, 'applications.txt')
    applications = []
    try:
        with open(applications_path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 7:
                    continue
                app = {
                    'application_id': int(fields[0]),
                    'job_id': int(fields[1]),
                    'applicant_name': fields[2],
                    'applicant_email': fields[3],
                    'status': fields[4],
                    'applied_date': fields[5],
                    'resume_id': int(fields[6])
                }
                applications.append(app)
    except FileNotFoundError:
        pass
    return applications


def write_applications(applications):
    applications_path = os.path.join(DATA_DIR, 'applications.txt')
    with open(applications_path, 'w', encoding='utf-8') as f:
        for a in applications:
            line = f"{a['application_id']}|{a['job_id']}|{a['applicant_name']}|{a['applicant_email']}|{a['status']}|{a['applied_date']}|{a['resume_id']}"
            f.write(line + '\n')


def read_resumes():
    resumes_path = os.path.join(DATA_DIR, 'resumes.txt')
    resumes = []
    try:
        with open(resumes_path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 6:
                    continue
                resume = {
                    'resume_id': int(fields[0]),
                    'applicant_name': fields[1],
                    'applicant_email': fields[2],
                    'filename': fields[3],
                    'upload_date': fields[4],
                    'summary': fields[5]
                }
                resumes.append(resume)
    except FileNotFoundError:
        pass
    return resumes


def write_resumes(resumes):
    resumes_path = os.path.join(DATA_DIR, 'resumes.txt')
    with open(resumes_path, 'w', encoding='utf-8') as f:
        for r in resumes:
            line = f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}"
            f.write(line + '\n')


def read_job_categories():
    # Not used directly for now, job category is stored in jobs.txt
    path = os.path.join(DATA_DIR, 'job_categories.txt')
    job_categories = []
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                line=line.strip()
                if not line:
                    continue
                fields = line.split('|')
                if len(fields) != 3:
                    continue
                mapping = {
                    'mapping_id': int(fields[0]),
                    'job_id': int(fields[1]),
                    'category_id': int(fields[2])
                }
                job_categories.append(mapping)
    except FileNotFoundError:
        pass
    return job_categories


@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    # Featured jobs could be the most recent or top 5 jobs
    jobs = read_jobs()
    companies = read_companies()

    # Build company lookup for company_name by company_id
    company_lookup = {c['company_id']: c['company_name'] for c in companies}

    # Sort jobs by posted_date descending
    jobs_sorted = sorted(jobs, key=lambda j: j['posted_date'], reverse=True)

    featured_jobs = []
    for job in jobs_sorted[:5]:
        featured_jobs.append({
            'job_id': job['job_id'],
            'title': job['title'],
            'company_name': company_lookup.get(job['company_id'], ""),
            'location': job['location'],
            'salary_min': job['salary_min'],
            'salary_max': job['salary_max']
        })

    # Navigation buttons context: not buttons actually but we pass their name as keys for frontend
    browse_jobs_button = True
    my_applications_button = True
    companies_button = True

    return render_template('dashboard.html', featured_jobs=featured_jobs,
                           browse_jobs_button=browse_jobs_button,
                           my_applications_button=my_applications_button,
                           companies_button=companies_button)


@app.route('/jobs')
def job_listings():
    jobs = read_jobs()
    companies = read_companies()
    categories = read_categories()

    # Prepare jobs with company name and category
    company_lookup = {c['company_id']: c['company_name'] for c in companies}

    jobs_for_template = []
    locations_set = set()
    for job in jobs:
        locations_set.add(job['location'])
        jobs_for_template.append({
            'job_id': job['job_id'],
            'title': job['title'],
            'company_name': company_lookup.get(job['company_id'], ""),
            'location': job['location'],
            'salary_min': job['salary_min'],
            'salary_max': job['salary_max'],
            'category': job['category']
        })

    categories_list = categories
    locations_list = sorted(locations_set)

    return render_template('job_listings.html', jobs=jobs_for_template, categories=categories_list, locations=locations_list)


@app.route('/job/<int:job_id>')
def job_details(job_id):
    jobs = read_jobs()
    companies = read_companies()

    job = next((j for j in jobs if j['job_id'] == job_id), None)
    if job is None:
        abort(404)

    company = next((c for c in companies if c['company_id'] == job['company_id']), None)
    if company is None:
        abort(404)

    job_context = {
        'job_id': job['job_id'],
        'title': job['title'],
        'company_name': company['company_name'],
        'location': job['location'],
        'salary_min': job['salary_min'],
        'salary_max': job['salary_max'],
        'description': job['description']
    }

    company_context = {
        'company_id': company['company_id'],
        'company_name': company['company_name']
    }

    return render_template('job_details.html', job=job_context, company=company_context)


@app.route('/job/<int:job_id>/apply', methods=['GET','POST'])
def application_form(job_id):
    jobs = read_jobs()
    job = next((j for j in jobs if j['job_id'] == job_id), None)
    if job is None:
        abort(404)

    if request.method == 'GET':
        job_context = {
            'job_id': job['job_id'],
            'title': job['title']
        }
        return render_template('application_form.html', job=job_context)

    # POST method - process application form
    applicant_name = request.form.get('applicant_name', '').strip()
    applicant_email = request.form.get('applicant_email', '').strip()
    cover_letter = request.form.get('cover_letter', '').strip()
    resume_file = request.files.get('resume_file')

    # Validate required fields
    if not applicant_name or not applicant_email or not cover_letter or not resume_file:
        # Could add flash messages but omitted for now
        return render_template('application_form.html', job={'job_id': job['job_id'], 'title': job['title']})

    # Save resume file
    filename = secure_filename(resume_file.filename)
    if filename == '':
        return render_template('application_form.html', job={'job_id': job['job_id'], 'title': job['title']})

    save_path = os.path.join(UPLOAD_FOLDER, filename)
    resume_file.save(save_path)

    # Save resume metadata
    resumes = read_resumes()
    max_resume_id = max([r['resume_id'] for r in resumes], default=0)

    # For summary, we'll do a simple placeholder since no content parsing required
    summary = f"Uploaded resume for {applicant_name}"
    upload_date = datetime.datetime.now().strftime('%Y-%m-%d')
    new_resume = {
        'resume_id': max_resume_id + 1,
        'applicant_name': applicant_name,
        'applicant_email': applicant_email,
        'filename': filename,
        'upload_date': upload_date,
        'summary': summary
    }
    resumes.append(new_resume)
    write_resumes(resumes)

    # Save application
    applications = read_applications()
    max_app_id = max([a['application_id'] for a in applications], default=0)

    new_application = {
        'application_id': max_app_id + 1,
        'job_id': job['job_id'],
        'applicant_name': applicant_name,
        'applicant_email': applicant_email,
        'status': 'Applied',
        'applied_date': upload_date,
        'resume_id': new_resume['resume_id']
    }
    applications.append(new_application)
    write_applications(applications)

    return redirect(url_for('application_tracking'))


@app.route('/applications')
def application_tracking():
    applications = read_applications()
    jobs = read_jobs()
    companies = read_companies()

    job_lookup = {j['job_id']: j for j in jobs}
    company_lookup = {c['company_id']: c for c in companies}

    applications_for_template = []
    for app in applications:
        job = job_lookup.get(app['job_id'])
        if not job:
            continue
        company = company_lookup.get(job['company_id'])
        if not company:
            continue

        app_dict = {
            'application_id': app['application_id'],
            'job_title': job['title'],
            'company_name': company['company_name'],
            'status': app['status'],
            'applied_date': app['applied_date']
        }
        applications_for_template.append(app_dict)

    status_filter_options = ['All', 'Applied', 'Under Review', 'Interview', 'Rejected']

    return render_template('application_tracking.html', applications=applications_for_template, status_filter_options=status_filter_options)


