@app.route('/job/<int:job_id>/apply', methods=['GET','POST'])
def application_form(job_id):
    jobs = read_jobs()
    job = next((j for j in jobs if j['job_id'] == job_id), None)
    if job is None:
        abort(404)

    if request.method == 'GET':
        job_context = {
            'job_id': job['job_id'],
            'title': job['title']
        }
        return render_template('application_form.html', job=job_context)

    # POST method - process application form
    applicant_name = request.form.get('applicant_name', '').strip()
    applicant_email = request.form.get('applicant_email', '').strip()
    cover_letter = request.form.get('cover_letter', '').strip()
    resume_file = request.files.get('resume_file')

    # Validate required fields
    if not applicant_name or not applicant_email or not cover_letter or not resume_file:
        # Could add flash messages but omitted for now
        return render_template('application_form.html', job={'job_id': job['job_id'], 'title': job['title']})

    # Save resume file
    filename = secure_filename(resume_file.filename)
    if filename == '':
        return render_template('application_form.html', job={'job_id': job['job_id'], 'title': job['title']})

    save_path = os.path.join(UPLOAD_FOLDER, filename)
    resume_file.save(save_path)

    # Save resume metadata
    resumes = read_resumes()
    max_resume_id = max([r['resume_id'] for r in resumes], default=0)

    # For summary, we'll do a simple placeholder since no content parsing required
    summary = f"Uploaded resume for {applicant_name}"
    upload_date = datetime.datetime.now().strftime('%Y-%m-%d')
    new_resume = {
        'resume_id': max_resume_id + 1,
        'applicant_name': applicant_name,
        'applicant_email': applicant_email,
        'filename': filename,
        'upload_date': upload_date,
        'summary': summary
    }
    resumes.append(new_resume)
    write_resumes(resumes)

    # Save application
    applications = read_applications()
    max_app_id = max([a['application_id'] for a in applications], default=0)

    new_application = {
        'application_id': max_app_id + 1,
        'job_id': job['job_id'],
        'applicant_name': applicant_name,
        'applicant_email': applicant_email,
        'status': 'Applied',
        'applied_date': upload_date,
        'resume_id': new_resume['resume_id']
